// claim-office.ts

const PROCESSING_FEE = 5;
const PLAIN_SWORD_NEWCOMER_PREMIUM = 115;
const PLAIN_AMULET_NEWCOMER_PREMIUM = 71;

export type Customer = {
  yearsInsured: number;
  previousQuotes: number;
};

export type Item = {
  type: string;
};

export type QuoteInput = {
  items: Item[];
  customer: Customer;
};

export const quote = (input: QuoteInput): number => {
  if (input.items.length === 0) return PROCESSING_FEE;
  if (input.items[0].type === "amulet") return PLAIN_AMULET_NEWCOMER_PREMIUM;
  return PLAIN_SWORD_NEWCOMER_PREMIUM;
};

