// claim-office.ts

const PROCESSING_FEE = 5;

const PLAIN_NEWCOMER_PREMIUM_BY_TYPE: Record<string, number> = {
  sword: 115,
  amulet: 71,
};

export type Customer = {
  yearsInsured: number;
  previousQuotes: number;
};

export type Item = {
  type: string;
};

export type QuoteInput = {
  items: Item[];
  customer: Customer;
};

export const quote = (input: QuoteInput): number => {
  if (input.items.length === 0) return PROCESSING_FEE;
  return PLAIN_NEWCOMER_PREMIUM_BY_TYPE[input.items[0].type];
};
